export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "10:47。佐伯把那張 PDF 影本放在桌面正中央。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "米色資料夾裡的其他文件被他推到旁邊。只有這一張。正面朝上。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這是藤川真理在美空失蹤前從醫療追蹤入口下載的裝置異常報告。列印版。不是螢幕截圖。紙面上有列印機留下的細微橫紋，右下角有一個日期戳。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "看右上角。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪把視線移到右上角。那裡有一個欄位。不是表格的一部分。是頁面生成的內部標記。列印時沒有被隱藏。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "兩行字。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "管理群：G07", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "個體：03", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯G07。個體 03。不是家屬圈的代號。不是佐伯編的。是文件自己寫的。是列印時系統自己吐出來的。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "藤川真理在美空失蹤前就下載了這份。醫院在美空失蹤前的門診紀錄裡，已經提過這份報告。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不是我們後來找到的。不是家屬圈成立後才出現的。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他在建證據鏈。下載時間早於失蹤。門診紀錄引用過同一份報告。所以 G07 不是我們補造的答案。是文件本來就有的。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯拿出一張空白紙。畫了一個表格。四列。從左到右。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "把四個孩子的代碼都列出來。標證據強度。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他寫得很慢。每一格都停一下。像在確認每一個字都站得住。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藤川美空。管理群 G07／個體 03。強。欄位名稱與外部日期皆清楚。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉悠真。G07／12。中。出現在第二階段預約頁截圖下方小字。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "水瀨葵。G07／08。中。出現在裝置報告條碼旁。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯蓮。G0?／17。弱。影本殘缺。不列入正式計數。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "蓮的殘缺。G0 後面那一位看不清。可能是 7。可能不是。不列入。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不列入。他連自己兒子的代碼都不列入。因為影本殘缺。因為看不清的那一位可能是 7 也可能不是。他不會因為希望它是 7 就當它是 7。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "三名。不是四名。三名目前已知異常案例，被文件標進 G07 管理群。第四名可能一致，但證據不足。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他停了一下。手指點在悠真那一列的 12 上。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "如果斜線後真的是個體號，這個群至少曾編到十二。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "十二。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "但我們不知道編號是否連續。也不知道會不會重複使用。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯至少編到十二。01 到 11 是誰。04 到 11 是誰。他們在哪裡。他們的家人在哪裡。他們是否也失蹤了。或者他們完全正常。或者 12 不是第十二個人。只是第十二筆紀錄。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "書面寫法。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "G07 編號上限目前至少可見 12。含義未明。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不寫「至少十二名受試者」。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "為什麼不寫？", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "因為 12 可能是序號。可能是批次。可能是重新編過的。寫成「受試者」就等於我們已經知道編號規則。我們不知道。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他拒絕把數字變成人。12 是 12。不是第十二個人。在他眼裡，在文件裡，12 只是 12。但在我眼裡——", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低頭看著表格裡悠真那一列。G07／12。中。出現在第二階段預約頁截圖下方小字。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻開私人筆記。在 G07／12 旁邊寫了一個字。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "悠真。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她已經寫過一次了。今天早上在家庭餐廳。現在又寫了一次。她不願弟弟只剩一個行政編號。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "接下來比刻痕。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他從桌邊拿出兩個信封。A 和 B。今天早上在家庭餐廳封存的。裡面是各自獨立的盲描記錄。A 是悠真小鏡子背面的描圖。B 是美空藥盒表面的描圖。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "規則跟早上一樣。不旋轉。不補畫。不重排。只記無需解釋便能對上的部分。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拆開信封 A。把描圖紙攤平。幾條短線。一條長斜線。間距不規則。有些筆畫可能只是磨損——早上已經標過了。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拆開信封 B。藥盒的刻痕更密。有幾道深一點。有幾道淺到像是劃過而不是刻過。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "佐伯把悠真的代碼 G07／12 寫在一張卡片上。放在描圖 A 旁邊。不疊。不描。只是放著。看。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "不硬拼。只看哪些線不用解釋就對得上。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著描圖 A 上的長斜線。再看 G07／12 裡的斜線。位置不同。方向不同。但描圖上有一組短線——如果對應數字——", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "長斜線旁邊有兩條短線。間距接近。如果斜線是分隔——", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "如果。不要寫「是」。寫「如果」。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他拿起筆。在記錄紙上寫。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "鏡背部分長短線與悠真代碼具有局部相符。不能稱作完整解碼。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他把美空的代碼 G07／03 寫在另一張卡片上。放在描圖 B 旁邊。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "藥盒上的刻痕更不規則。有幾道深線的間距像是被擠在一起。但其中一組——", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "藥盒部分刻痕與美空代碼具有局部相符。仍不能稱作完整解碼。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "最保守推測。悠真與美空可能把自己的管理碼抄在不容易被研究方收回的私人物上。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯不容易被收回的私人物。鏡子。藥盒。不是筆記本。不是手機。不是紙。是隨身攜帶、不容易被系統清除的東西。悠真選了鏡子。美空選了藥盒。他們知道紙和手機裡的東西會被收回。會被改。會消失。所以他們刻在更硬的東西上。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯悠真。你是不是知道自己的代碼會被刪掉。你是不是故意把它刻在鏡背上。你是不是故意把鏡子留給我。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說出來。她看著描圖 A 上那些長短線。局部相符。不是完整解碼。佐伯的措辭精確到像在用尺量每一個詞。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "今天不推以下任何一項。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "G07 是能力等級。不推。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "G07 是實驗組。不推。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "G07 會導致失蹤。不推。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "七條線就是 G07。不推。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "小鏡子一定能解鎖其他設備。不推。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我知道。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她又看了一眼私人筆記。G07／12。悠真。兩個字並排。一個是系統給的編號。一個是她給的名字。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "11:30。佐伯把刻痕描圖重新放回信封。沒有封口。但也沒有讓澪帶走。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.SaekiTatsuya, character: "佐伯達也", dialogue: "描圖留在這裡。妳的官方筆記可以寫「局部相符」。私人筆記不要帶進下一場。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.SaekiTatsuya_Determined },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）⋯⋯他知道我有私人筆記。他不看。但他知道。他讓我寫。但他不讓它進入證據鏈。", background: Background.Chapter_12_Ch12_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把私人筆記合上。放進背包側袋。官方筆記攤在桌上。上面只有佐伯的措辭。局部相符。不能稱作完整解碼。含義未明。", background: Background.Chapter_12_Ch12_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "桌上的 PDF 還在。管理群：G07。個體：03。兩行字。列印時系統自己吐出來的。像一個不小心露出的名牌。", background: Background.Chapter_12_Ch12_Act5_S0 },
];
